// src/App.js - WITH LOGIN AUTH
import React, { useState, useEffect } from 'react';
import {
  Package,
  ShoppingCart,
  Receipt,
  TrendingUp,
  Droplet,
  Cookie,
  Wheat,
  Flame,
  Candy,
  Box,
  RefreshCw,
  Lock,
  LogOut,
  Users,
  Calendar,
  Phone,
  KeyRound,
} from 'lucide-react';
import {
  LineChart,
  Line,
  PieChart,
  Pie,
  Cell,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  Legend,
  ResponsiveContainer,
} from 'recharts';
import axios from 'axios';
import './App.css';

// Backend API URL
const API_BASE_URL = 'https://makhanchor-backend.onrender.com/api';

// Create axios instance
const api = axios.create({
  baseURL: API_BASE_URL,
  headers: {
    'Content-Type': 'application/json',
  },
});

// Add token to requests if available
api.interceptors.request.use(
  (config) => {
    const token = localStorage.getItem('dashboard_token');
    if (token) {
      config.headers.Authorization = `Bearer ${token}`;
    }
    return config;
  },
  (error) => {
    return Promise.reject(error);
  }
);

// Handle responses and errors
api.interceptors.response.use(
  (response) => response,
  (error) => {
    if (error.response?.status === 401) {
      // Token expired or invalid - logout user
      localStorage.removeItem('dashboard_token');
      localStorage.removeItem('dashboard_user');
      window.location.reload();
    }
    return Promise.reject(error);
  }
);

const App = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [mobile, setMobile] = useState('');
  const [password, setPassword] = useState('');
  const [loginError, setLoginError] = useState('');
  const [loginLoading, setLoginLoading] = useState(false);
  const [loading, setLoading] = useState(false);
  const [dashboardData, setDashboardData] = useState(null);
  const [lastUpdated, setLastUpdated] = useState(null);
  const [userName, setUserName] = useState('');

  // Check if already authenticated
  useEffect(() => {
  const token = localStorage.getItem('dashboard_token');
  const userStr = localStorage.getItem('dashboard_user');
  if (token && userStr && userStr !== 'undefined') {
    try {
      const user = JSON.parse(userStr);
      setIsAuthenticated(true);
      setUserName(user.name);
    } catch (e) {
      // Clear corrupted data
      localStorage.removeItem('dashboard_token');
      localStorage.removeItem('dashboard_user');
    }
  }
}, []);

  // Fetch data when authenticated
  useEffect(() => {
    if (isAuthenticated) {
      fetchDashboardData();
      // Auto refresh every 5 minutes
      const interval = setInterval(fetchDashboardData, 5 * 60 * 1000);
      return () => clearInterval(interval);
    }
  }, [isAuthenticated]);

  const handleLogin = async (e) => {
    e.preventDefault();
    setLoginLoading(true);
    setLoginError('');

    try {
      // Call login API
      const response = await axios.post(`${API_BASE_URL}/auth/login`, {
        mobile,
        password,
      });

      if (response.data.success) {
  localStorage.setItem('dashboard_token', response.data.token);
  localStorage.setItem('dashboard_user', JSON.stringify(response.data.user));  // changed .data to .user
  setUserName(response.data.user.name);  // changed .data to .user
  setIsAuthenticated(true);
}
    } catch (error) {
      console.error('Login error:', error);
      setLoginError(
        error.response?.data?.message || 'Invalid credentials. Please try again.'
      );
    } finally {
      setLoginLoading(false);
    }
  };

  const handleLogout = () => {
    localStorage.removeItem('dashboard_token');
    localStorage.removeItem('dashboard_user');
    setIsAuthenticated(false);
    setMobile('');
    setPassword('');
    setDashboardData(null);
    setUserName('');
  };

  const fetchDashboardData = async () => {
    setLoading(true);
    try {
      const today = new Date().toISOString().split('T')[0];
      const firstDayOfMonth = new Date(new Date().getFullYear(), new Date().getMonth(), 1)
        .toISOString()
        .split('T')[0];

      const last7Days = new Date();
      last7Days.setDate(last7Days.getDate() - 7);
      const last7DaysStr = last7Days.toISOString().split('T')[0];

      // Fetch all data using api instance with token
      const [
        todayProd,
        todaySales,
        monthlyProd,
        monthlySales,
        allTimeProd,
        allTimeSales,
        inventory,
        rawMaterials,
        todayMisc,
        monthlyMisc,
        last7DaysProd,
        last7DaysSales,
        allSales,
      ] = await Promise.all([
        api.get(`/production/stats?startDate=${today}&endDate=${today}`),
        api.get(`/sales/stats?startDate=${today}&endDate=${today}`),
        api.get(`/production/stats?startDate=${firstDayOfMonth}&endDate=${today}`),
        api.get(`/sales/stats?startDate=${firstDayOfMonth}&endDate=${today}`),
        api.get(`/production/stats`),
        api.get(`/sales/stats`),
        api.get(`/inventory/all/stats`),
        api.get(`/raw-materials/stats/all`),
        api.get(`/miscellaneous/stats?startDate=${today}&endDate=${today}`),
        api.get(`/miscellaneous/stats?startDate=${firstDayOfMonth}&endDate=${today}`),
        api.get(`/production?startDate=${last7DaysStr}&endDate=${today}&limit=1000`),
        api.get(`/sales?startDate=${last7DaysStr}&endDate=${today}&limit=1000`),
        api.get(`/sales?startDate=${firstDayOfMonth}&endDate=${today}&limit=1000`),
      ]);

      const trendData = processWeeklyTrend(
        last7DaysProd.data.data,
        last7DaysSales.data.data
      );

      const topCustomers = processTopCustomers(allSales.data.data);

      setDashboardData({
        today: {
          production: todayProd.data.data.totalProduction || 0,
          sales: todaySales.data.data.totalSales || 0,
          spending: todayMisc.data.data.rangeSpending || todayMisc.data.data.totalSpending || 0,
        },
        monthly: {
          production: monthlyProd.data.data.totalProduction || 0,
          sales: monthlySales.data.data.totalSales || 0,
          spending: monthlyMisc.data.data.rangeSpending || monthlyMisc.data.data.totalSpending || 0,
        },
        allTime: {
          production: allTimeProd.data.data.totalProduction || 0,
          sales: allTimeSales.data.data.totalSales || 0,
          remaining: allTimeProd.data.data.totalRemaining || 0,
        },
        inventory: {
          maida: inventory.data.data.maida?.currentStock || 0,
          oil: inventory.data.data.oil?.currentStock || 0,
          ghee: inventory.data.data.ghee?.currentStock || 0,
        },
        rawMaterials: {
          suji: rawMaterials.data.data.suji?.totalPurchased || 0,
          sugar: rawMaterials.data.data.sugar?.totalPurchased || 0,
          salt: rawMaterials.data.data.salt?.totalPurchased || 0,
          gasBig: rawMaterials.data.data.gas?.totalBigTanks || 0,
          gasSmall: rawMaterials.data.data.gas?.totalSmallTanks || 0,
        },
        trendData,
        topCustomers,
      });

      setLastUpdated(new Date());
    } catch (error) {
      console.error('Error fetching dashboard data:', error);
      if (error.response?.status === 401) {
        alert('Session expired. Please login again.');
        handleLogout();
      } else {
        alert('Failed to load dashboard data');
      }
    } finally {
      setLoading(false);
    }
  };

  const processWeeklyTrend = (production, sales) => {
    const dailyData = {};

    production.forEach(p => {
      const date = p.date.split('T')[0];
      if (!dailyData[date]) {
        dailyData[date] = { date, production: 0, sales: 0 };
      }
      dailyData[date].production += p.packets;
    });

    sales.forEach(s => {
      const date = s.date.split('T')[0];
      if (!dailyData[date]) {
        dailyData[date] = { date, production: 0, sales: 0 };
      }
      dailyData[date].sales += s.packets;
    });

    return Object.values(dailyData)
      .sort((a, b) => new Date(a.date) - new Date(b.date))
      .map(d => ({
        date: new Date(d.date).toLocaleDateString('en-IN', { day: '2-digit', month: 'short' }),
        production: d.production,
        sales: d.sales,
      }));
  };

  const toTotalDabbas = (packetValue) => {
    const packets = Math.floor(packetValue);
    const dabbas = Math.round((packetValue - packets) * 100);
    return (packets * 16) + dabbas;
  };

  const processTopCustomers = (sales) => {
    const customerMap = {};

    sales.forEach(s => {
      const customer = s.customer || 'Walk-in';
      if (!customerMap[customer]) {
        customerMap[customer] = { name: customer, dabbas: 0, packets: 0 };
      }
      customerMap[customer].dabbas += toTotalDabbas(s.packets);
      customerMap[customer].packets = customerMap[customer].dabbas / 16;
    });

    return Object.values(customerMap)
      .sort((a, b) => b.dabbas - a.dabbas)
      .slice(0, 5);
  };

  // Login Screen
  if (!isAuthenticated) {
    return (
      <div className="min-h-screen flex items-center justify-center p-4 bg-gradient-to-br from-orange-100 via-orange-50 to-yellow-100">
        <div className="glass-card w-full max-w-md p-8 animate-slide-up">
          <div className="text-center mb-8">
            <div className="w-20 h-20 mx-auto mb-4 rounded-full bg-gradient-to-br from-orange-400 to-orange-600 flex items-center justify-center">
              <Lock className="text-white" size={40} />
            </div>
            <h1 className="text-3xl font-bold text-gray-800 mb-2">MakhanChor</h1>
            <p className="text-gray-600">Dashboard Login</p>
          </div>

          <form onSubmit={handleLogin} className="space-y-6">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">
                Mobile Number
              </label>
              <div className="relative">
                <Phone className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={20} />
                <input
                  type="tel"
                  inputMode="numeric"
                  maxLength="10"
                  value={mobile}
                  onChange={(e) => {
                    setMobile(e.target.value);
                    setLoginError('');
                  }}
                  className="w-full pl-11 pr-4 py-3 border-2 border-gray-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-orange-500 focus:border-transparent bg-white/50 backdrop-blur-sm"
                  placeholder="Enter mobile number"
                  required
                  autoFocus
                />
              </div>
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">
                Password
              </label>
              <div className="relative">
                <KeyRound className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={20} />
                <input
                  type="password"
                  value={password}
                  onChange={(e) => {
                    setPassword(e.target.value);
                    setLoginError('');
                  }}
                  className="w-full pl-11 pr-4 py-3 border-2 border-gray-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-orange-500 focus:border-transparent bg-white/50 backdrop-blur-sm"
                  placeholder="Enter password"
                  required
                />
              </div>
              {loginError && (
                <p className="text-red-500 text-sm mt-2">{loginError}</p>
              )}
            </div>

            <button
              type="submit"
              disabled={loginLoading}
              className="w-full bg-gradient-to-r from-orange-500 to-orange-600 text-white py-3 rounded-xl font-semibold hover:from-orange-600 hover:to-orange-700 transition-all duration-200 shadow-lg hover:shadow-xl disabled:opacity-50"
            >
              {loginLoading ? 'Logging in...' : 'Login'}
            </button>
          </form>

          <div className="mt-6 text-center text-xs text-gray-500">
            Secured access for authorized personnel only
          </div>
        </div>
      </div>
    );
  }

  // Loading State
  if (loading && !dashboardData) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gradient-to-br from-orange-100 via-orange-50 to-yellow-100">
        <div className="text-center">
          <RefreshCw className="animate-spin text-orange-500 mx-auto mb-4" size={48} />
          <p className="text-gray-600 text-lg">Loading dashboard...</p>
        </div>
      </div>
    );
  }

  if (!dashboardData) return null;

  const inventoryData = [
    { name: 'Maida', value: dashboardData.inventory.maida, color: '#f59e0b' },
    { name: 'Oil', value: dashboardData.inventory.oil, color: '#eab308' },
    { name: 'Ghee', value: dashboardData.inventory.ghee, color: '#f97316' },
  ];

  return (
    <div className="min-h-screen bg-gradient-to-br from-orange-100 via-orange-50 to-yellow-100 p-4 md:p-6">
      {/* Header */}
      <div className="glass-card p-4 md:p-6 mb-6">
        <div className="flex items-center justify-between flex-wrap gap-4">
          <div>
            <h1 className="text-2xl md:text-3xl font-bold text-gray-800 mb-1">
              MakhanChor Dashboard
            </h1>
            <p className="text-sm text-gray-600">
              Welcome, {userName} • {lastUpdated && `Last updated: ${lastUpdated.toLocaleTimeString('en-IN')}`}
            </p>
          </div>
          <div className="flex gap-2">
            <button
              onClick={fetchDashboardData}
              disabled={loading}
              className="p-3 rounded-xl bg-white/50 hover:bg-white/80 transition-all duration-200"
              title="Refresh"
            >
              <RefreshCw className={`text-orange-600 ${loading ? 'animate-spin' : ''}`} size={20} />
            </button>
            <button
              onClick={handleLogout}
              className="p-3 rounded-xl bg-red-500/20 hover:bg-red-500/30 transition-all duration-200"
              title="Logout"
            >
              <LogOut className="text-red-600" size={20} />
            </button>
          </div>
        </div>
      </div>

      {/* Today's Summary */}
      <div className="mb-6">
        <h2 className="text-lg font-semibold text-gray-800 mb-3 flex items-center gap-2">
          <Calendar size={20} className="text-orange-600" />
          Today's Summary
        </h2>
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
          <StatCard
            icon={Package}
            title="Production"
            value={dashboardData.today.production}
            subtitle="packets"
            color="blue"
          />
          <StatCard
            icon={ShoppingCart}
            title="Sales"
            value={dashboardData.today.sales}
            subtitle="packets"
            color="green"
          />
          <StatCard
            icon={Receipt}
            title="Spending"
            value={`₹${dashboardData.today.spending.toLocaleString('en-IN')}`}
            subtitle="miscellaneous"
            color="purple"
          />
        </div>
      </div>

      {/* Monthly Overview */}
      <div className="mb-6">
        <h2 className="text-lg font-semibold text-gray-800 mb-3">This Month</h2>
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
          <StatCard
            icon={Package}
            title="Production"
            value={dashboardData.monthly.production}
            subtitle="packets"
            color="blue"
            large
          />
          <StatCard
            icon={ShoppingCart}
            title="Sales"
            value={dashboardData.monthly.sales}
            subtitle="packets"
            color="green"
            large
          />
          <StatCard
            icon={Receipt}
            title="Spending"
            value={`₹${(dashboardData.monthly.spending / 1000).toFixed(1)}K`}
            subtitle="total"
            color="purple"
            large
          />
        </div>
      </div>

      {/* Charts Row */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mb-6">
        {/* Trend Chart */}
        <div className="glass-card p-4 md:p-6">
          <h3 className="text-lg font-semibold text-gray-800 mb-4">Last 7 Days Trend</h3>
          <ResponsiveContainer width="100%" height={250}>
            <LineChart data={dashboardData.trendData}>
              <CartesianGrid strokeDasharray="3 3" stroke="#e5e7eb" />
              <XAxis dataKey="date" tick={{ fill: '#6b7280', fontSize: 12 }} />
              <YAxis tick={{ fill: '#6b7280', fontSize: 12 }} />
              <Tooltip
                contentStyle={{
                  backgroundColor: 'rgba(255, 255, 255, 0.95)',
                  border: '1px solid #e5e7eb',
                  borderRadius: '12px',
                  backdropFilter: 'blur(10px)',
                }}
              />
              <Legend />
              <Line
                type="monotone"
                dataKey="production"
                stroke="#3b82f6"
                strokeWidth={3}
                name="Production"
                dot={{ r: 4 }}
              />
              <Line
                type="monotone"
                dataKey="sales"
                stroke="#10b981"
                strokeWidth={3}
                name="Sales"
                dot={{ r: 4 }}
              />
            </LineChart>
          </ResponsiveContainer>
        </div>

        {/* Inventory Pie */}
        <div className="glass-card p-4 md:p-6">
          <h3 className="text-lg font-semibold text-gray-800 mb-4">Current Stock</h3>
          <ResponsiveContainer width="100%" height={250}>
            <PieChart>
              <Pie
                data={inventoryData}
                cx="50%"
                cy="50%"
                labelLine={false}
                label={({ name, value }) => `${name}: ${value}`}
                outerRadius={80}
                fill="#8884d8"
                dataKey="value"
              >
                {inventoryData.map((entry, index) => (
                  <Cell key={`cell-${index}`} fill={entry.color} />
                ))}
              </Pie>
              <Tooltip />
            </PieChart>
          </ResponsiveContainer>
        </div>
      </div>

      {/* Bottom Grid */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* Raw Materials */}
        <div className="glass-card p-4 md:p-6">
          <h3 className="text-lg font-semibold text-gray-800 mb-4 flex items-center gap-2">
            <Box size={20} className="text-orange-600" />
            Raw Materials Stock
          </h3>
          <div className="space-y-3">
            <MaterialRow
              icon={Wheat}
              name="Suji"
              value={dashboardData.rawMaterials.suji}
              unit="packets"
              color="yellow"
            />
            <MaterialRow
              icon={Candy}
              name="Sugar"
              value={dashboardData.rawMaterials.sugar}
              unit="packets"
              color="pink"
            />
            <MaterialRow
              icon={Box}
              name="Salt"
              value={dashboardData.rawMaterials.salt}
              unit="packets"
              color="gray"
            />
            <MaterialRow
              icon={Flame}
              name="Gas (Big)"
              value={dashboardData.rawMaterials.gasBig}
              unit="tanks"
              color="red"
            />
            <MaterialRow
              icon={Flame}
              name="Gas (Small)"
              value={dashboardData.rawMaterials.gasSmall}
              unit="tanks"
              color="orange"
            />
          </div>
        </div>

        {/* Top Customers */}
        <div className="glass-card p-4 md:p-6">
          <h3 className="text-lg font-semibold text-gray-800 mb-4 flex items-center gap-2">
            <Users size={20} className="text-green-600" />
            Top Customers (This Month)
          </h3>
          {dashboardData.topCustomers.length === 0 ? (
            <p className="text-center text-gray-500 py-8">No data available</p>
          ) : (
            <div className="space-y-3">
              {dashboardData.topCustomers.map((customer, index) => (
                <div key={index} className="flex items-center gap-3">
                  <div className="flex-shrink-0 w-10 h-10 rounded-full bg-gradient-to-br from-green-400 to-green-600 flex items-center justify-center text-white font-bold">
                    {index + 1}
                  </div>
                  <div className="flex-1 min-w-0">
                    <div className="flex items-center justify-between mb-1">
                      <span className="font-semibold text-gray-800 truncate">
                        {customer.name}
                      </span>
                      <span className="text-sm font-bold text-green-600 ml-2">
                        {customer.packets.toFixed(1)}
                      </span>
                    </div>
                    <div className="w-full bg-gray-200/50 rounded-full h-2 overflow-hidden">
                      <div
                        className="bg-gradient-to-r from-green-400 to-green-600 h-full rounded-full"
                        style={{
                          width: `${(customer.dabbas / dashboardData.topCustomers[0].dabbas) * 100}%`,
                        }}
                      ></div>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>

      {/* Overall Stats */}
      <div className="mt-6 glass-card p-4 md:p-6">
        <h3 className="text-lg font-semibold text-gray-800 mb-4">Overall Statistics</h3>
        <div className="grid grid-cols-2 md:grid-cols-3 gap-4">
          <div className="text-center">
            <div className="text-3xl font-bold text-blue-600">
              {dashboardData.allTime.production}
            </div>
            <div className="text-sm text-gray-600 mt-1">Total Production</div>
          </div>
          <div className="text-center">
            <div className="text-3xl font-bold text-green-600">
              {dashboardData.allTime.sales}
            </div>
            <div className="text-sm text-gray-600 mt-1">Total Sales</div>
          </div>
          <div className="text-center">
            <div className="text-3xl font-bold text-orange-600">
              {dashboardData.allTime.remaining}
            </div>
            <div className="text-sm text-gray-600 mt-1">Stock Remaining</div>
          </div>
        </div>
      </div>
    </div>
  );
};

// Stat Card Component
const StatCard = ({ icon: Icon, title, value, subtitle, color, large }) => {
  const colorClasses = {
    blue: 'from-blue-400 to-blue-600',
    green: 'from-green-400 to-green-600',
    purple: 'from-purple-400 to-purple-600',
    orange: 'from-orange-400 to-orange-600',
  };

  return (
    <div className="glass-card p-4 md:p-6">
      <div className="flex items-center justify-between mb-3">
        <Icon className={`bg-gradient-to-br ${colorClasses[color]} bg-clip-text text-transparent`} size={large ? 32 : 28} />
        <span className="text-xs font-medium text-gray-500 uppercase">{title}</span>
      </div>
      <div className={`${large ? 'text-4xl' : 'text-3xl'} font-bold text-gray-800 mb-1`}>
        {value}
      </div>
      <div className="text-sm text-gray-600">{subtitle}</div>
    </div>
  );
};

// Material Row Component
const MaterialRow = ({ icon: Icon, name, value, unit, color }) => {
  const colorClasses = {
    yellow: 'text-yellow-600',
    pink: 'text-pink-600',
    gray: 'text-gray-600',
    red: 'text-red-600',
    orange: 'text-orange-600',
  };

  return (
    <div className="flex items-center justify-between p-3 rounded-xl bg-white/30">
      <div className="flex items-center gap-3">
        <Icon className={colorClasses[color]} size={20} />
        <span className="font-medium text-gray-800">{name}</span>
      </div>
      <div className="text-right">
        <div className="font-bold text-gray-800">{value}</div>
        <div className="text-xs text-gray-500">{unit}</div>
      </div>
    </div>
  );
};

export default App;
